const byCitySlug: Record<string, ClimateProfile> = {};
for (const profile of climateProfiles) {
  byCitySlug[profile.citySlug] = profile;
}

/** Runtime integrity guard — throws (failing `next build`) on any invalid profile. */
function assertClimateIntegrity(profiles: readonly ClimateProfile[]): void {
  const errors: string[] = [];
  const seen = new Set<string>();
  for (const p of profiles) {
    if (seen.has(p.citySlug)) errors.push(`duplicate citySlug: ${p.citySlug}`);
    seen.add(p.citySlug);
    if (p.monthly.length !== 12) errors.push(`${p.citySlug}: expected 12 months, got ${p.monthly.length}`);
    for (const m of p.monthly) {
      if (!(m.avgHighC >= m.avgLowC)) errors.push(`${p.citySlug}/${m.month}: high < low`);
      if (!(m.precipitationMm >= 0)) errors.push(`${p.citySlug}/${m.month}: negative precipitation`);
      if (!(m.rainyDays >= 0 && m.rainyDays <= 31)) errors.push(`${p.citySlug}/${m.month}: rainyDays out of range`);
      if (!(m.sunshineHours >= 0)) errors.push(`${p.citySlug}/${m.month}: negative sunshine`);
    }
    if (!(p.comfortScore >= 0 && p.comfortScore <= 100)) errors.push(`${p.citySlug}: comfortScore out of range`);
    if (!p.climateZone) errors.push(`${p.citySlug}: missing climateZone`);
  }
  if (errors.length > 0) {
    throw new Error(`climate integrity failure:\n${errors.join("\n")}`);
  }
}

assertClimateIntegrity(climateProfiles);

export function getClimate(citySlug: string): ClimateProfile | undefined {
  return byCitySlug[citySlug];
}

export function hasClimate(citySlug: string): boolean {
  return Object.prototype.hasOwnProperty.call(byCitySlug, citySlug);
}

export function getAllClimateProfiles(): readonly ClimateProfile[] {
  return climateProfiles;
}
